class ErpModule:
    def __init__(self, name, is_active):
        self.name = name
        self.is_active = is_active

function runMRP(demand, inventory) {
  return demand > inventory ? (demand - inventory) : 0;
}

function reconcile(ledgerValue, bankValue) {
  return ledgerValue === bankValue;
}

function consolidate(subBalances) {
  return subBalances.reduce((acc, curr) => acc + curr, 0);
}

function forecastNextMonth(prevData) {
  const avg = prevData.reduce((a,b) => a+b) / prevData.length;
  return avg * 1.05; // 5% growth projection
}
